 class=\"px-6 py-4 whitespace-nowrap text-sm text-gray-500\">\n                                        {{ $resource->updated_at ? $resource->updated_at->format('d/m/Y H:i') : '-' }}\n                                    </td>\n                                    <td class=\"px-6 py-4 whitespace-nowrap text-sm font-medium\">\n                                        <div class=\"flex items-center gap-2\">\n                                            <a href=\"{{ route('admin.resources.edit', [$resource->id, $resource->source_table]) }}\" class=\"btn text-blue-600 hover:text-blue-900\">\n                                                <svg class=\"w-5 h-5\" fill=\"none\" viewBox=\"0 0 24 24\" stroke=\"currentColor\">\n                                                    <path stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\" d=\"M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z\"/>\n                                                </svg>\n                                            </a>\n                                            <button onclick=\"confirmDelete({{ $resource->id }}, '{{ $resource->source_table }}', '{{ $resource->title }}')\" class=\"btn text-red-600 hover:text-red-900\">\n                                                <svg class=\"w-5 h-5\" fill=\"none\" viewBox=\"0 0 24 24\" stroke=\"currentColor\">\n                                                    <path stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\" d=\"M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16\"/>\n                                                </svg>\n                                            </button>\n                                        </div>\n                                    </td>\n                                </tr>\n                            @endforeach\n                        </tbody