</svg>\n                </div>\n                <div class=\"flex-1\">\n                    <h3 class=\"text-lg font-semibold text-gray-900\">Confirmar Eliminación</h3>\n                    <p class=\"text-sm text-gray-600 mt-1\">¿Está seguro de que desea eliminar el recurso <span id=\"resourceTitle\" class=\"font-medium\"></span>? Esta acción no se puede deshacer.</p>\n                </div>\n            </div>\n            \n            <div class=\"flex justify-end gap-3 mt-6\">\n                <button onclick=\"closeDeleteModal()\" class=\"btn px-4 py-2 border border-gray-300 rounded-lg text-gray-700 hover:bg-gray-50 transition\">\n                    No\n                </button>\n                <button onclick=\"deleteResource()\" class=\"btn px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition\">\n                    Sí, Eliminar\n                </button>\n            </div>\n        </div>\n    </div>\n</div>\n\n<script>\nlet resourceToDelete = null;\n\nfunction confirmDelete(id, type, title) {\n    resourceToDelete = { id, type };\n    document.getElementById('resourceTitle').textContent = title;\n    document.getElementById('deleteModal').classList.remove('hidden');\n    document.getElementById('deleteModal').classList.add('flex');\n}\n\nfunction closeDeleteModal() {\n    resourceToDelete = null;\n    document.getElementById('deleteModal').classList.add('hidden');\n    document.getElementById('deleteModal').classList.remove('flex');\n}\n\nfunction deleteResource() {\n    if (!resourceToDelete) return;\n    \n    fetch(`/admin/gestionar-recursos/${resourceToDelete.id}/${resourceToDelete.type}`, {\n        method: 'DELETE',\n        headers: {\n            'X-CSRF-TOKEN': document.querySelector('meta[name=\"csrf-token\"]').getAttribute('content'),\n            'Accept': 'application/json'\n        }\n    })\n    .then(response => response.json())\n    .then(data => {\n        if (data.success) {\n            closeDeleteModal();\n            showToast(data.message, 'success');\n            location.reload();\n        } else {\n            showToast(data.message, 'danger');\n        }\n    })\n    .catch(error => {\n        showToast('Error al eliminar el recurso', 'danger');\n    });\n}\n\n// Cerrar modal con Escape\ndocument.addEventListener('keydown', function(e) {\n    if (e.key === 'Escape') {\n        closeDeleteModal();\n    }\n});\n</script>\n@endsection